(function () {
  "use strict";

  var MAIN_OFFSET = 0x8030;
  var ZIP_OFFSET = 0xB375;
  var EASYCHAT_OFFSET = 0x8007;

  var MAIN_HEX = "";
  var ZIP_HEX = "000000000000FF";
  var EASYCHAT_BY_LANG = {
    E: "0D02010523020205290604050D0D01043D050105040402050F0505053806020D",
    F: "0D02010523020205290604050202010525052603050402050F0505053A06020D",
    D: "0D0201052302000529060405020701043D05010507040005320405050C04020D",
    S: "0D020105230200051B0704050202400538050105070400053605010532040005",
    I: "430701050B020305010D1D020C0B01050802050D070400053E050E0615070005",
  };

  function hexToBytes(hex) {
    var normalized = String(hex || "").replace(/[^0-9a-fA-F]/g, "");
    if (normalized.length % 2 !== 0) {
      throw new Error("Invalid hex payload length.");
    }
    var out = new Uint8Array(normalized.length / 2);
    for (var i = 0; i < normalized.length; i += 2) {
      out[i / 2] = parseInt(normalized.substr(i, 2), 16);
    }
    return out;
  }

  var MAIN_BYTES = hexToBytes(MAIN_HEX);
  var ZIP_BYTES = hexToBytes(ZIP_HEX);
  var EASYCHAT_BYTES_BY_LANG = {
    E: hexToBytes(EASYCHAT_BY_LANG.E),
    F: hexToBytes(EASYCHAT_BY_LANG.F),
    D: hexToBytes(EASYCHAT_BY_LANG.D),
    S: hexToBytes(EASYCHAT_BY_LANG.S),
    I: hexToBytes(EASYCHAT_BY_LANG.I),
  };

  var fileInput = document.getElementById("save-file-input");
  var fileNameNode = document.getElementById("save-file-name");
  var convertBtn = document.getElementById("save-convert-btn");
  var statusNode = document.getElementById("save-converter-status");

  if (!fileInput || !convertBtn || !statusNode) {
    return;
  }

  function setStatus(text) {
    statusNode.textContent = String(text || "");
  }

  function setSelectedFileName(file) {
    if (!fileNameNode) {
      return;
    }
    fileNameNode.textContent = (file && file.name) ? String(file.name) : "No file chosen";
  }

  function getSelectedLanguage() {
    var checked = document.querySelector('input[name="save-lang"]:checked');
    return checked ? String(checked.value || "").toUpperCase() : "";
  }

  function splitFileName(name) {
    var safe = String(name || "save.sav");
    var lastDot = safe.lastIndexOf(".");
    if (lastDot <= 0) {
      return { base: safe, ext: "" };
    }
    return {
      base: safe.substring(0, lastDot),
      ext: safe.substring(lastDot),
    };
  }

  function minimalSanity(file, bytes) {
    if (!file || !file.name) {
      throw new Error("Select a .sav file first.");
    }

    if (!/\.sav$/i.test(file.name)) {
      throw new Error("Must be a .sav file.");
    }

    var size = bytes.length;
    if (size < 28000 || size > 36000) {
      throw new Error("Unexpected save size: " + size + " bytes (expected ~32 KB).");
    }
  }

  function isAlreadyMobile(bytes) {
    if (bytes.length < MAIN_OFFSET + MAIN_BYTES.length) {
      return false;
    }
    for (var i = 0; i < MAIN_BYTES.length; i++) {
      if (bytes[MAIN_OFFSET + i] !== MAIN_BYTES[i]) {
        return false;
      }
    }
    return true;
  }

  function writeBytes(target, offset, payload) {
    for (var i = 0; i < payload.length; i++) {
      target[offset + i] = payload[i];
    }
  }

  function applyPayload(inputBytes, langCode) {
    var easyBytes = EASYCHAT_BYTES_BY_LANG[langCode];
    if (!easyBytes) {
      throw new Error("Choose the save's language.");
    }

    var outLength = Math.max(
      inputBytes.length,
      MAIN_OFFSET + MAIN_BYTES.length,
      ZIP_OFFSET + ZIP_BYTES.length,
      EASYCHAT_OFFSET + easyBytes.length
    );

    var out = new Uint8Array(outLength);
    out.set(inputBytes, 0);

    writeBytes(out, MAIN_OFFSET, MAIN_BYTES);
    writeBytes(out, ZIP_OFFSET, ZIP_BYTES);
    writeBytes(out, EASYCHAT_OFFSET, easyBytes);

    return out;
  }

  function triggerDownload(bytes, fileName) {
    var blob = new Blob([bytes], { type: "application/octet-stream" });
    var url = URL.createObjectURL(blob);
    var a = document.createElement("a");
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(function () {
      URL.revokeObjectURL(url);
    }, 0);
  }

  fileInput.addEventListener("change", function () {
    var file = fileInput.files && fileInput.files[0] ? fileInput.files[0] : null;
    setSelectedFileName(file);
  });

  setSelectedFileName(null);

  convertBtn.addEventListener("click", function () {
    var file = fileInput.files && fileInput.files[0] ? fileInput.files[0] : null;
    if (!file) {
      setStatus("Error: Select a .sav file first.");
      return;
    }

    convertBtn.disabled = true;
    setStatus("Reading file...");

    file.arrayBuffer().then(function (buffer) {
      var inputBytes = new Uint8Array(buffer);

      minimalSanity(file, inputBytes);

      var lang = getSelectedLanguage();
      if (!EASYCHAT_BYTES_BY_LANG[lang]) {
        throw new Error("Choose the save's language.");
      }

      if (isAlreadyMobile(inputBytes)) {
        setStatus("Already Mobile Adapter compatible.");
        return;
      }

      var parts = splitFileName(file.name);
      var outputName = parts.base + ".sav";

      var outBytes = applyPayload(inputBytes, lang);
      triggerDownload(outBytes, outputName);

      setStatus("Success.");
    }).catch(function (err) {
      setStatus("Conversion failed: " + (err && err.message ? err.message : String(err)));
    }).finally(function () {
      convertBtn.disabled = false;
    });
  });
})();
